// Loop over input items and add date check fields
for (const item of $input.all()) {
  const inputDate = new Date(item.json.date || '2024-09-24T02:52:24.000Z');
  const currentDate = new Date();
  const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

  // Check if date is within last 30 days
  const isWithinLast30Days = inputDate >= thirtyDaysAgo;

  // Calculate days difference
  const daysDifference = Math.floor((currentDate - inputDate) / (1000 * 60 * 60 * 24));

  // Format date as 1-Jan-2025
  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 
                  'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const formattedDate = `${inputDate.getDate()}-${months[inputDate.getMonth()]}-${inputDate.getFullYear()}`;

  item.json.isWithinLast30Days = isWithinLast30Days;
  item.json.daysDifference = daysDifference;
  item.json.thirtyDaysAgo = thirtyDaysAgo.toISOString();
  item.json.formattedDate = formattedDate;
}

return $input.all();

